class PluginSandbox {
  constructor(pluginCode, pluginName) {
    this.pluginName = pluginName;
    this.pluginCode = pluginCode;
    this.sandbox = this.createSandbox();
  }

  createSandbox() {
    const sandbox = {
      console: {
        log: (...args) => console.log(`[Plugin:${this.pluginName}]`, ...args),
        error: (...args) => console.error(`[Plugin:${this.pluginName}]`, ...args),
        warn: (...args) => console.warn(`[Plugin:${this.pluginName}]`, ...args)
      },
      Buffer: Buffer,
      setTimeout: setTimeout,
      clearTimeout: clearTimeout,
      setInterval: setInterval,
      clearInterval: clearInterval,
      JSON: JSON,
      Math: Math,
      Date: Date,
      String: String,
      Number: Number,
      Boolean: Boolean,
      Array: Array,
      Object: Object,
      RegExp: RegExp,
      Error: Error,
      Promise: Promise,
      Map: Map,
      Set: Set,
      WeakMap: WeakMap,
      WeakSet: WeakSet,
      Symbol: Symbol,
      crypto: {
        randomBytes: crypto.randomBytes,
        createHash: crypto.createHash,
        createHmac: crypto.createHmac
      },
      module: { exports: {} },
      exports: {}
    };
    
    sandbox.global = sandbox;
    return sandbox;
  }

  execute() {
    try {
      const script = new vm.Script(`
        (function(module, exports) {
          ${this.pluginCode}
          return module.exports;
        })(module, exports);
      `);
      
      const context = vm.createContext(this.sandbox);
      const result = script.runInContext(context, {
        timeout: 5000,
        displayErrors: true
      });
      
      return result || this.sandbox.module.exports;
    } catch (error) {
      throw new Error(`Plugin ${this.pluginName} execution failed: ${error.message}`);
    }
  }
}

class PluginManager {
  constructor() {
    this.plugins = [];
    this.allowedPluginPaths = [];
  }

  setAllowedPaths(paths) {
    this.allowedPluginPaths = paths.map(p => path.resolve(p));
  }

  validatePluginPath(pluginPath) {
    const resolvedPath = path.resolve(pluginPath);
    
    if (!fs.existsSync(resolvedPath)) {
      throw new Error(`Plugin path does not exist: ${pluginPath}`);
    }

    const isAllowed = this.allowedPluginPaths.some(allowedPath => {
      return resolvedPath.startsWith(allowedPath);
    });

    if (!isAllowed) {
      throw new Error(`Plugin path not in allowed directories: ${pluginPath}`);
    }

    return resolvedPath;
  }

  sanitizePluginCode(code) {
    const dangerousPatterns = [
      /require\s*\(\s*['"`]child_process['"`]\s*\)/gi,
      /require\s*\(\s*['"`]fs['"`]\s*\)/gi,
      /require\s*\(\s*['"`]net['"`]\s*\)/gi,
      /require\s*\(\s*['"`]dgram['"`]\s*\)/gi,
      /require\s*\(\s*['"`]cluster['"`]\s*\)/gi,
      /process\s*\.\s*exit/gi,
      /process\s*\.\s*kill/gi,
      /process\s*\.\s*binding/gi,
      /eval\s*\(/gi,
      /Function\s*\(/gi,
      /\.constructor\s*\(/gi
    ];

    for (const pattern of dangerousPatterns) {
      if (pattern.test(code)) {
        throw new Error(`Plugin code contains dangerous pattern: ${pattern}`);
      }
    }

    return code;
  }

  loadPluginFromFile(filePath) {
    const validatedPath = this.validatePluginPath(filePath);
    const code = fs.readFileSync(validatedPath, 'utf8');
    const sanitizedCode = this.sanitizePluginCode(code);
    const pluginName = path.basename(filePath, path.extname(filePath));
    
    const sandbox = new PluginSandbox(sanitizedCode, pluginName);
    const plugin = sandbox.execute();
    
    this.validatePlugin(plugin);
    this.plugins.push({ name: pluginName, plugin });
    
    return plugin;
  }

  loadPluginFromCode(code, name) {
    const sanitizedCode = this.sanitizePluginCode(code);
    const sandbox = new PluginSandbox(sanitizedCode, name);
    const plugin = sandbox.execute();
    
    this.validatePlugin(plugin);
    this.plugins.push({ name, plugin });
    
    return plugin;
  }

  validatePlugin(plugin) {
    if (typeof plugin !== 'object' || plugin === null) {
      throw new Error('Plugin must export an object');
    }

    const validHooks = ['onRequest', 'onResponse', 'onError'];
    const pluginHooks = Object.keys(plugin).filter(key => validHooks.includes(key));

    if (pluginHooks.length === 0) {
      throw new Error('Plugin must implement at least one hook: onRequest, onResponse, or onError');
    }

    pluginHooks.forEach(hook => {
      if (typeof plugin[hook] !== 'function') {
        throw new Error(`Plugin hook ${hook} must be a function`);
      }
    });
  }

  async executeHook(hookName, context) {
    for (const { name, plugin } of this.plugins) {
      if (plugin[hookName]) {
        try {
          const result = await Promise.race([
            plugin[hookName](context),
            new Promise((_, reject) => 
              setTimeout(() => reject(new Error('Plugin timeout')), 5000)
            )
          ]);
          
          if (result === false) {
            return false;
          }
        } catch (error) {
          console.error(`Plugin ${name} hook ${hookName} failed:`, error.message);
          if (plugin.onError) {
            try {
              await plugin.onError({ error, context, hook: hookName });
            } catch (e) {
              console.error(`Plugin ${name} error handler failed:`, e.message);
            }
          }
        }
      }
    }
    return true;
  }
}

class APIGateway {
  constructor(config = {}) {
    this.config = {
      port: config.port || 3000,
      targetHost: config.targetHost || 'localhost',
      targetPort: config.targetPort || 8080,
      targetProtocol: config.targetProtocol || 'http',
      allowedPluginPaths: config.allowedPluginPaths || [process.cwd()],
      ...config
    };
    
    this.pluginManager = new PluginManager();
    this.pluginManager.setAllowedPaths(this.config.allowedPluginPaths);
  }

  loadPlugins() {
    if (this.config.pluginFiles && Array.isArray(this.config.pluginFiles)) {
      this.config.pluginFiles.forEach(filePath => {
        try {
          this.pluginManager.loadPluginFromFile(filePath);
          console.log(`Loaded plugin from file: ${filePath}`);
        } catch (error) {
          console.error(`Failed to load plugin from ${filePath}:`, error.message);
        }
      });
    }

    if (this.config.pluginCode && Array.isArray(this.config.pluginCode)) {
      this.config.pluginCode.forEach((pluginDef, index) => {
        try {
          const name = pluginDef.name || `inline-plugin-${index}`;
          this.pluginManager.loadPluginFromCode(pluginDef.code, name);
          console.log(`Loaded inline plugin: ${name}`);
        } catch (error) {
          console.error(`Failed to load inline plugin ${index}:`, error.message);
        }
      });
    }

    const envPluginCode = process.env.GATEWAY_PLUGIN_CODE;
    if (envPluginCode) {
      try {
        this.pluginManager.loadPluginFromCode(envPluginCode, 'env-plugin');
        console.log('Loaded plugin from environment variable');
      } catch (error) {
        console.error('Failed to load plugin from environment:', error.message);
      }
    }
  }

  async handleRequest(req, res) {
    const requestContext = {
      method: req.method,
      url: req.url,
      headers: { ...req.headers },
      body: null,
      metadata: {}
    };

    let body = [];
    for await (const chunk of req) {
      body.push(chunk);
    }
    requestContext.body = Buffer.concat(body);

    const shouldContinue = await this.pluginManager.executeHook('onRequest', requestContext);
    
    if (shouldContinue === false) {
      res.writeHead(403, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Request blocked by plugin' }));
      return;
    }

    this.proxyRequest(requestContext, res);
  }

  proxyRequest(requestContext, clientRes) {
    const options = {
      hostname: this.config.targetHost,
      port: this.config.targetPort,
      path: requestContext.url,
      method: requestContext.method,
      headers: requestContext.headers
    };

    const protocol = this.config.targetProtocol === 'https' ? https : http;

    const proxyReq = protocol.request(options, async (proxyRes) => {
      const responseContext = {
        statusCode: proxyRes.statusCode,
        headers: { ...proxyRes.headers },
        body: null,
        metadata: requestContext.metadata
      };

      let body = [];
      for await (const chunk of proxyRes) {
        body.push(chunk);
      }
      responseContext.body = Buffer.concat(body);

      await this.pluginManager.executeHook('onResponse', responseContext);

      clientRes.writeHead(responseContext.statusCode, responseContext.headers);
      clientRes.end(responseContext.body);
    });

    proxyReq.on('error', async (error) => {
      console.error('Proxy request error:', error.message);
      
      const errorContext = {
        error,
        request: requestContext,
        metadata: requestContext.metadata
      };
      
      await this.pluginManager.executeHook('onError', errorContext);

      if (!clientRes.headersSent) {
        clientRes.writeHead(502, { 'Content-Type': 'application/json' });
        clientRes.end(JSON.stringify({ error: 'Bad Gateway' }));
      }
    });

    if (requestContext.body && requestContext.body.length > 0) {
      proxyReq.write(requestContext.body);
    }
    
    proxyReq.end();
  }

  start() {
    this.loadPlugins();

    const server = http.createServer((req, res) => {
      this.handleRequest(req, res).catch(error => {
        console.error('Request handling error:', error);
        if (!res.headersSent) {
          res.writeHead(500, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: 'Internal Server Error' }));
        }
      });
    });

    server.listen(this.config.port, () => {
      console.log(`API Gateway listening on port ${this.config.port}`);
      console.log(`Proxying to ${this.config.targetProtocol}://${this.config.targetHost}:${this.config.targetPort}`);
    });

    return server;
  }
}

